import { CommandPalette as CommandPaletteRoot, type CommandPaletteProps } from "./command-palette";
import { CommandPaletteContent, type CommandPaletteContentProps } from "./command-palette-content";
import { CommandPaletteInput, type CommandPaletteInputProps } from "./command-palette-input";
import { CommandPaletteList, type CommandPaletteListProps } from "./command-palette-list";
import { CommandPaletteGroup, type CommandPaletteGroupProps } from "./command-palette-group";
import { CommandPaletteFooter, type CommandPaletteFooterProps } from "./command-palette-footer";
import { CommandPaletteItem, type CommandPaletteItemProps } from "./command-palette-item";
import { CommandPaletteEmpty, type CommandPaletteEmptyProps } from "./command-palette-empty";

const CommandPalette = Object.assign(CommandPaletteRoot, {
  Content: CommandPaletteContent,
  Input: CommandPaletteInput,
  List: CommandPaletteList,
  Group: CommandPaletteGroup,
  Item: CommandPaletteItem,
  Empty: CommandPaletteEmpty,
  Footer: CommandPaletteFooter,
});

export { CommandPalette, type CommandPaletteProps };
export { CommandPaletteContent, type CommandPaletteContentProps };
export { CommandPaletteInput, type CommandPaletteInputProps };
export { CommandPaletteList, type CommandPaletteListProps };
export { CommandPaletteGroup, type CommandPaletteGroupProps };
export { CommandPaletteItem, type CommandPaletteItemProps };
export { CommandPaletteEmpty, type CommandPaletteEmptyProps };
export { CommandPaletteFooter, type CommandPaletteFooterProps };

"use client";

import type { ReactNode } from "react";
import { useCommandPaletteState, type UseCommandPaletteStateOptions } from "./use-command-palette-state";
import { CommandPaletteContext } from "./command-palette-context";

export interface CommandPaletteProps extends UseCommandPaletteStateOptions {
  children: ReactNode;
}

export function CommandPalette({
  children,
  ...stateProps
}: CommandPaletteProps) {
  const contextValue = useCommandPaletteState(stateProps);

  return (
    <CommandPaletteContext value={contextValue}>
      {children}
    </CommandPaletteContext>
  );
}

"use client";

import { createContext, useContext, type RefObject, type KeyboardEvent as ReactKeyboardEvent } from "react";

export interface CommandPaletteContextValue {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  selectedId: string | null;
  onActivate: (id: string) => void;
  search: string;
  onSearchChange: (value: string) => void;
  shouldFilter: boolean;
  filter: (value: string, search: string) => boolean;
  itemCount: number;
  registerItem: (id: string) => void;
  unregisterItem: (id: string) => void;
  setItemCallback: (id: string, onSelect?: () => void) => void;
  getItemCallback: (id: string) => (() => void) | undefined;
  listId: string;
  listRef: RefObject<HTMLDivElement | null>;
  navKeyDown: (event: ReactKeyboardEvent) => void;
}

export const CommandPaletteContext = createContext<CommandPaletteContextValue | undefined>(undefined);

export function useCommandPaletteContext() {
  const context = useContext(CommandPaletteContext);
  if (!context) throw new Error("CommandPalette compound components must be used within a CommandPalette");
  return context;
}

"use client";

import { type ReactNode, useRef, useEffect } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";
import { DialogShell } from "../shared/dialog-shell";

const contentVariants = cva(
  "border-2 border-border shadow-[0_0_40px_rgba(0,0,0,0.5)] bg-background relative flex flex-col max-h-[80vh] m-auto outline outline-1 outline-border/50 outline-offset-[1px] focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      size: { sm: "max-w-sm", md: "max-w-xl", lg: "max-w-2xl" },
    },
    defaultVariants: { size: "md" },
  }
);

function getLiveText(search: string, itemCount: number): string {
  if (!search) return "";
  if (itemCount === 0) return "No results";
  return `${itemCount} result${itemCount === 1 ? "" : "s"} available`;
}

export interface CommandPaletteContentProps extends VariantProps<typeof contentVariants> {
  children: ReactNode;
  className?: string;
  label?: string;
}

export function CommandPaletteContent({ children, className, size, label = "Command palette" }: CommandPaletteContentProps) {
  const { open, onOpenChange, search, onSearchChange, itemCount } = useCommandPaletteContext();
  const previousFocusRef = useRef<Element | null>(null);

  useEffect(() => {
    if (open) {
      previousFocusRef.current = document.activeElement;
    } else if (previousFocusRef.current) {
      const el = previousFocusRef.current as HTMLElement;
      previousFocusRef.current = null;
      el.focus?.();
    }
  }, [open]);

  return (
    <DialogShell
      open={open}
      onBackdropClick={() => onOpenChange(false)}
      onCancel={() => search ? onSearchChange("") : onOpenChange(false)}
      className={cn(contentVariants({ size }), className)}
      aria-label={label}
    >
      {children}
      <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">
        {getLiveText(search, itemCount)}
      </div>
    </DialogShell>
  );
}

"use client";

import { cn } from "@/lib/utils";
import type { KeyboardEvent as ReactKeyboardEvent, ReactNode, Ref } from "react";
import { useCommandPaletteContext } from "./command-palette-context";

export interface CommandPaletteInputProps {
  placeholder?: string;
  label?: string;
  prefix?: ReactNode;
  suffix?: ReactNode;
  onKeyDown?: (event: ReactKeyboardEvent<HTMLInputElement>) => void;
  className?: string;
  ref?: Ref<HTMLInputElement>;
}

export function CommandPaletteInput({
  placeholder = "Type a command...",
  label = "Command search",
  prefix,
  suffix,
  onKeyDown,
  className,
  ref,
}: CommandPaletteInputProps) {
  const { open, search, onSearchChange, navKeyDown, selectedId, listId } = useCommandPaletteContext();

  return (
    <div className={cn("flex items-center p-4 border-b border-border/60", className)}>
      {prefix ?? <span className="text-foreground text-[20px] mr-3 font-bold select-none">&gt;</span>}
      <input
        ref={ref}
        type="text"
        role="combobox"
        aria-label={label}
        aria-expanded={open}
        aria-autocomplete="list"
        aria-controls={listId}
        aria-activedescendant={selectedId ?? undefined}
        value={search}
        onChange={(e) => onSearchChange(e.target.value)}
        onKeyDown={(e) => { if (e.key === " ") { onKeyDown?.(e); return; } navKeyDown(e); onKeyDown?.(e); }}
        placeholder={placeholder}
        className="w-full bg-transparent border-none p-0 text-foreground placeholder-muted-foreground/70 font-mono text-sm caret-foreground h-6 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background"
      />
      {suffix ?? (
        <div className="text-[10px] font-bold text-muted-foreground border border-border px-1.5 py-0.5 rounded ml-2 select-none">
          ESC
        </div>
      )}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { composeRefs } from "@/lib/compose-refs";
import { useCommandPaletteContext } from "./command-palette-context";
import type { ReactNode, Ref } from "react";

export interface CommandPaletteListProps {
  children: ReactNode;
  className?: string;
  ref?: Ref<HTMLDivElement>;
}

export function CommandPaletteList({ children, className, ref }: CommandPaletteListProps) {
  const { listRef, listId } = useCommandPaletteContext();
  return (
    <div id={listId} ref={composeRefs(listRef, ref)} role="listbox" className={cn("flex-1 overflow-y-auto p-2 space-y-1", className)}>
      {children}
    </div>
  );
}

"use client";

import { useId, type ReactNode } from "react";
import { cn } from "@/lib/utils";

