      <div id={headingId} className="px-2 py-1.5 text-[10px] uppercase font-bold text-muted-foreground/70 tracking-wider">{heading}</div>
      <div className="space-y-1">{children}</div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import type { ReactNode } from "react";
import { useCommandPaletteContext } from "./command-palette-context";

export interface CommandPaletteEmptyProps {
  children: ReactNode;
  className?: string;
}

export function CommandPaletteEmpty({ children, className }: CommandPaletteEmptyProps) {
  const { itemCount, search } = useCommandPaletteContext();
  if (itemCount > 0 || !search) return null;
  return (
    <div className={cn("py-6 text-center text-sm text-muted-foreground", className)}>
      {children}
    </div>
  );
}

