"use client";

import { useLayoutEffect, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useCommandPaletteContext } from "./command-palette-context";

const itemVariants = cva(
  "w-full text-left flex items-center justify-between px-3 py-2.5 text-sm group cursor-pointer select-none",
  {
    variants: {
      selected: {
        true: "bg-foreground text-background font-medium",
        false: "text-foreground hover:bg-secondary hover:text-foreground transition-colors",
      },
      disabled: {
        true: "opacity-50 cursor-not-allowed",
      },
    },
    defaultVariants: { selected: false },
  }
);

export interface CommandPaletteItemProps {
  id: string;
  value?: string;
  icon?: ReactNode;
  shortcut?: string;
  onSelect?: () => void;
  disabled?: boolean;
  children: ReactNode;
  className?: string;
}

export function CommandPaletteItem({
  id, value, icon, shortcut, onSelect, disabled = false, children, className,
}: CommandPaletteItemProps) {
  const { selectedId, onActivate, registerItem, unregisterItem, setItemCallback, search, shouldFilter, filter } = useCommandPaletteContext();

  const searchValue = value ?? id;
  const isVisible = !shouldFilter || !search || filter(searchValue, search);

  useLayoutEffect(() => {
    if (disabled || !isVisible) return;
    registerItem(id);
    return () => unregisterItem(id);
  }, [id, disabled, isVisible]);

  useLayoutEffect(() => {
    setItemCallback(id, disabled ? undefined : onSelect);
    return () => setItemCallback(id, undefined);
  }, [id, onSelect, disabled]);

  if (!isVisible) return null;

  const isSelected = selectedId === id;

  return (
    <div
      id={id}
      role="option"
      data-value={id}
      aria-selected={isSelected}
      aria-disabled={disabled || undefined}
      onClick={() => { if (disabled) return; onActivate(id); }}
      className={cn(itemVariants({ selected: isSelected, disabled }), className)}
    >
      <div className="flex items-center gap-3">
        {icon && (
          <span className={cn("text-[18px]", !isSelected && "text-muted-foreground group-hover:text-foreground")}>
            {icon}
          </span>
        )}
        <span>{children}</span>
      </div>
      {isSelected && (
        <span className="text-[10px] font-bold opacity-70">{"\u21B5"}</span>
      )}
      {!isSelected && shortcut && (
        <span className="text-[10px] text-muted-foreground/70 group-hover:text-muted-foreground font-mono">{shortcut}</span>
      )}
    </div>
  );
}

"use client";

import { useLayoutEffect, useEffectEvent, useId, useMemo, useRef } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { useControllableState } from "@/hooks/use-controllable-state";
import { matchesSearch } from "@/lib/search";
import { useItemRegistry } from "./use-item-registry";
import type { CommandPaletteContextValue } from "./command-palette-context";

const defaultFilter = matchesSearch;

export interface UseCommandPaletteStateOptions {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  search?: string;
  onSearchChange?: (value: string) => void;
  selectedId?: string | null;
  onSelectedIdChange?: (id: string | null) => void;
  onActivate?: (id: string) => void;
  shouldFilter?: boolean;
  filter?: (value: string, search: string) => boolean;
}

export function useCommandPaletteState({
  open: controlledOpen,
  onOpenChange,
  search: controlledSearch,
  onSearchChange: controlledOnSearchChange,
  selectedId: controlledSelectedId,
  onSelectedIdChange,
  onActivate,
  shouldFilter = true,
  filter: filterProp,
}: UseCommandPaletteStateOptions): CommandPaletteContextValue {
  const filter = filterProp ?? defaultFilter;
  const [isOpen, setIsOpen] = useControllableState({ value: controlledOpen, defaultValue: false, onChange: onOpenChange });
  const [search, setSearch] = useControllableState({ value: controlledSearch, defaultValue: "", onChange: controlledOnSearchChange });
  const [selectedId, setSelectedId, isSelectedControlled] = useControllableState<string | null>({ value: controlledSelectedId, defaultValue: null, onChange: onSelectedIdChange });
  const { items, itemCount, registerItem, unregisterItem, setItemCallback, getItemCallback } = useItemRegistry();
  const listRef = useRef<HTMLDivElement>(null);
  const paletteId = useId();

  const handleOpenChange = useEffectEvent((next: boolean) => {
    if (!next) setSearch("");
    setIsOpen(next);
  });

  const handleActivate = useEffectEvent((id: string) => {
    getItemCallback(id)?.();
    onActivate?.(id);
    handleOpenChange(false);
  });

  const { onKeyDown: rawNavKeyDown } = useNavigation({
    containerRef: listRef,
    role: "option",
    wrap: true,
    value: selectedId,
    onValueChange: setSelectedId,
    onEnter: handleActivate,
    enabled: isOpen,
  });
  const navKeyDown = useEffectEvent(rawNavKeyDown);

  const autoSelectFirst = useEffectEvent(() => {
    if (isSelectedControlled) return;
    setSelectedId((currentId) => {
      if (currentId && items.includes(currentId)) return currentId;
      return items[0] ?? null;
    });
  });

  useLayoutEffect(() => {
    autoSelectFirst();
  }, [items]);

  return useMemo(() => ({
    open: isOpen, onOpenChange: handleOpenChange, selectedId,
    onActivate: handleActivate, search, onSearchChange: setSearch,
    shouldFilter, filter, itemCount,
    registerItem, unregisterItem, setItemCallback, getItemCallback,
    listId: `${paletteId}-list`, listRef, navKeyDown,
  }), [isOpen, selectedId, search, shouldFilter, filter, itemCount, registerItem, unregisterItem, setItemCallback, getItemCallback, paletteId]);
}

"use client";

import { useState, useEffectEvent, useRef } from "react";

export function useItemRegistry() {
  const [items, setItems] = useState<string[]>([]);
  const callbackMapRef = useRef(new Map<string, (() => void) | undefined>());

  const registerItem = useEffectEvent((id: string) => {
    setItems(prev => prev.includes(id) ? prev : [...prev, id]);
  });

  const unregisterItem = useEffectEvent((id: string) => {
    callbackMapRef.current.delete(id);
    setItems(prev => prev.filter(i => i !== id));
  });

  const setItemCallback = useEffectEvent((id: string, onSelect?: () => void) => {
    callbackMapRef.current.set(id, onSelect);
  });

  const getItemCallback = (id: string) => callbackMapRef.current.get(id);

  return { items, itemCount: items.length, registerItem, unregisterItem, setItemCallback, getItemCallback };
}
